interface Item<T> {
  id: number;
  data: T;
}

class Store<T> {
  private cache: Map<number, Item<T>>;

  constructor() {
    this.cache = new Map();
  }

  addItem(id: number, data: T): void {
    if (this.cache.has(id)) {
      throw new Error('Item with given id already exists.');
    }
    this.cache.set(id, { id, data });
  }

  getItem(id: number): Item<T> | undefined {
    return this.cache.get(id);
  }

  HasItem(id: number): boolean {
    return this.cache.has(id);
  }
}

// Example usage:\nconst store = new Store<number>();
store.addItem(1, 10);
console.log(store.getItem(1));  // Output: { id: 1, data: 10 }
const item = store.HasItem(1); // Output: true
